from __future__ import annotations


def merge_logs(streams, detect_gaps=False):
    by_key = {}
    seqs = {}
    for stream in streams:
        for record in stream:
            key = (record.get('source'), record.get('seq'))
            if key not in by_key:
                by_key[key] = dict(record)
            seqs.setdefault(record.get('source'), set()).add(record.get('seq'))
    merged = sorted(by_key.values(), key=lambda row: row.get('ts', 0))
    if not detect_gaps:
        return merged
    gaps = []
    for source, values in seqs.items():
        for seq in range(min(values), max(values) + 1):
            if seq not in values:
                gaps.append({'source': source, 'missing_seq': seq})
    return merged, gaps

